/**
 * Showcase: when(), unless(), whenOr(), unlessOr()
 * Renders as conditional nodes with true/false branches.
 */
import { createWorkflow, ok, type AsyncResult } from "awaitly";
import { when, unless, whenOr, unlessOr } from "awaitly/conditional";

const audit = async (): AsyncResult<boolean, "AUDIT_FAILED"> => ok(true);
const compute = async (): AsyncResult<number, "COMPUTE_ERROR"> => ok(99);

export const conditionalWorkflow = createWorkflow("conditionalWorkflow", { audit, compute });

export type ConditionalResult = { a: boolean; b: number };

export async function runConditional(isPremium: boolean): Promise<ConditionalResult> {
  return await conditionalWorkflow.run(async ({ step, deps }): Promise<ConditionalResult> => {
    await when(isPremium, () => step("whenStep", () => deps.audit()));
    await unless(isPremium, () => step("unlessStep", () => deps.compute()));
    const a = await whenOr(isPremium, () => step("whenOrStep", () => deps.audit()), false);
    const b = await unlessOr(isPremium, () => step("unlessOrStep", () => deps.compute()), 0);
    return { a, b };
  });
}

/**
 * Showcase: switch (expression) { case ... } with steps in branches.
 * Renders as a switch node with case labels.
 */
import { createWorkflow, ok, type AsyncResult } from "awaitly";

const adminAction = async (): AsyncResult<void, "ADMIN_ERROR"> => ok(undefined);
const userAction = async (): AsyncResult<void, "USER_ERROR"> => ok(undefined);
const defaultAction = async (): AsyncResult<void, never> => ok(undefined);

export const switchWorkflow = createWorkflow("switchWorkflow", {
  adminAction,
  userAction,
  defaultAction,
});

export async function runSwitch(role: string) {
  return await switchWorkflow.run(async ({ step, deps }) => {
    switch (role) {
      case "admin":
        await step("admin", () => deps.adminAction(), { errors: ["ADMIN_ERROR"] });
        break;
      case "user":
        await step("user", () => deps.userAction(), { errors: ["USER_ERROR"] });
        break;
      default:
        await step("default", () => deps.defaultAction());
        break;
    }
    return role;
  });
}

/**
 * Showcase: for, while, for-of, for-in loops with steps inside.
 * Renders as loop nodes (for, for-of, for-in, while).
 */
import { createWorkflow, ok, type AsyncResult } from "awaitly";

const processItem = async (id: string): AsyncResult<void, "PROCESS_ERROR"> => ok(undefined);

export const loopWorkflow = createWorkflow("loopWorkflow", { processItem });

export async function runLoops() {
  return await loopWorkflow.run(async ({ step, deps }) => {
    for (let i = 0; i < 3; i++) {
      await step("forStep", () => deps.processItem(String(i)), { errors: ["PROCESS_ERROR"] });
    }
    const items = ["a", "b"];
    for (const item of items) {
      await step("forOfStep", () => deps.processItem(item), { errors: ["PROCESS_ERROR"] });
    }
    const obj = { x: 1 };
    for (const key in obj) {
      await step("forInStep", () => deps.processItem(key), { errors: ["PROCESS_ERROR"] });
    }
    let n = 0;
    while (n < 2) {
      await step("whileStep", () => deps.processItem(String(n)), { errors: ["PROCESS_ERROR"] });
      n++;
    }
    return "done";
  });
}

/**
 * Showcase: workflow ref — calling another workflow.
 * Renders as a workflow-ref node [[childWorkflow]].
 */
import { createWorkflow, ok, type AsyncResult } from "awaitly";

/** User shape returned by fetchUser step */
interface User {
  id: string;
}

/** Enriched shape returned by child workflow */
interface Enriched {
  id: string;
  enriched: true;
}

const enrich = async (id: string): AsyncResult<Enriched, "ENRICH_ERROR"> =>
  ok({ id, enriched: true });
const fetchUser = async (id: string): AsyncResult<User, "NOT_FOUND"> => ok({ id });

export const childWorkflow = createWorkflow("childWorkflow", { enrich });
export const parentWorkflow = createWorkflow("parentWorkflow", { fetchUser });

export async function runParent(userId: string): Promise<{ user: User; enriched: Enriched }> {
  return await parentWorkflow.run(
    async ({ step, deps }): Promise<{ user: User; enriched: Enriched }> => {
      const user = await step("getUser", () => deps.fetchUser(userId), { errors: ["NOT_FOUND"] });
      const enriched = await childWorkflow.run(async ({ step: s, deps: d }) => {
        return await s("enrich", () => d.enrich(user.id), { errors: ["ENRICH_ERROR"] });
      });
      return { user, enriched };
    }
  );
}

/**
 * Showcase: complex — parallel inside conditional, step.if, step.parallel, step.forEach.
 * Renders as nested subgraphs and decision nodes.
 */
import { createWorkflow, ok, type AsyncResult } from "awaitly";

const fetchA = async (): AsyncResult<string, "ERR"> => ok("a");
const fetchB = async (): AsyncResult<string, "ERR"> => ok("b");
const processItem = async (x: string): AsyncResult<string, "ERR"> => ok(x);

export const complexWorkflow = createWorkflow("complexWorkflow", { fetchA, fetchB, processItem });

export type ComplexResult = { a: string; b: string } | { a: string };

export async function runComplex(doParallel: boolean, items: string[]): Promise<ComplexResult> {
  return await complexWorkflow.run(async ({ step, deps }): Promise<ComplexResult> => {
    if (step.if("choice", "doParallel", () => doParallel)) {
      const { a, b } = await step.parallel("fetchBoth", {
        a: () => deps.fetchA(),
        b: () => deps.fetchB(),
      });
      await step.forEach("processAll", items, {
        run: (item) => deps.processItem(item),
      });
      return { a, b };
    } else {
      const a = await step("fetchAOnly", () => deps.fetchA(), { errors: ["ERR"] });
      return { a };
    }
  });
}

